    assert CountPositiveAfterDiv(a, d) == CountPositiveAfterDiv(a[..|a|-1], d) + lastNeg;
    assert CountNegative(a) == CountNegative(a[..|a|-1]) + lastNeg;
    assert CountPositiveAfterDiv(a, d) == CountNegative(a);
  }
}

method BePositive(a: seq<int>) returns (d: int)
  ensures d != 0 ==> -1000 <= d <= 1000
                      && CountPositiveAfterDiv(a, d) >= CeilHalf(|a|)
  ensures d == 0 ==> (forall d' :: d' == 0 || CountPositiveAfterDiv(a, d') < CeilHalf(|a|))
{
  var n := |a|;
  var pcount := 0;
  var ncount := 0;
  var zcount := 0;
  var i := 0;
  while i < n
    invariant 0 <= i <= n
    invariant pcount == CountPositive(a[..i])
    invariant ncount == CountNegative(a[..i])
  {

    if a[i] > 0 {
      pcount := pcount + 1;
    } else if a[i] < 0 {
      ncount := ncount + 1;
    } else {
      zcount := zcount + 1;
    }
    i := i + 1;
  }

  var half := (n + 1) / 2;
  if pcount >= half {
    d := 1;
    CountPosDivPos(a, 1);
    assert CountPositiveAfterDiv(a, 1) == CountPositive(a);
    assert CountPositive(a) >= half;
  } else if ncount >= half {
    d := -1;
    CountPosDivNeg(a, -1);
    assert CountPositiveAfterDiv(a, -1) == CountNegative(a);
    assert CountNegative(a) >= half;
  } else {
    d := 0;
    forall d' | d' != 0
      ensures CountPositiveAfterDiv(a, d') < CeilHalf(|a|)
    {
      if d' > 0 {
        CountPosDivPos(a, d');
        assert CountPositiveAfterDiv(a, d') == CountPositive(a);
        assert CountPositive(a) < half;
      } else {
        CountPosDivNeg(a, d');
        assert CountPositiveAfterDiv(a, d') == CountNegative(a);
        assert CountNegative(a) < half;
      }
    }
  }
}
